await (async (page) => {
  await page.evaluate(() => {
    // 找到 Permissions level 下拉框中的按钮
    const allCombos = document.querySelectorAll('[role="combobox"]');
    let targetCombo = null;
    for (const combo of allCombos) {
      const placeholder = combo.querySelector('[placeholder]');
      if (placeholder && placeholder.getAttribute('placeholder') === 'Select') {
        targetCombo = combo;
        break;
      }
      // 或者检查是否有 "Select..." 文本
      if (combo.textContent.includes('Select...')) {
        targetCombo = combo;
        break;
      }
    }

    if (targetCombo) {
      const btn = targetCombo.querySelector('button');
      if (btn) {
        btn.click();
        return 'clicked level combo';
      }
    }

    // 尝试另一种方法 - 直接找 downshift toggle buttons
    const toggleBtns = document.querySelectorAll('[id*="downshift"][id*="toggle"]');
    if (toggleBtns.length >= 2) {
      toggleBtns[1].click(); // 第二个 toggle 是 level
      return 'clicked second toggle';
    }

    return 'not found';
  });
  await page.waitForTimeout(2000);
  return 'done';
})(page);
