        g.scopes && g.scopes.some(s => s.includes('zone'))
      );

      const policies = [];

      // Account 级别 policy
      if (accountGroups.length > 0) {
        const groups = accountGroups.slice(0, 300);
        policies.push({
          effect: 'allow',
          resources: { 'com.cloudflare.api.account.*': '*' },
          permission_groups: groups.map(g => ({ id: g.id }))
        });
      }

      // Zone 级别 policy
      if (zoneGroups.length > 0) {
        const groups = zoneGroups.slice(0, 300);
        policies.push({
          effect: 'allow',
          resources: { 'com.cloudflare.api.account.zone.*': '*' },
          permission_groups: groups.map(g => ({ id: g.id }))
        });
      }

      const createResp = await fetch('/api/v4/user/tokens', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          name: '全权限-持久化-道',
